#define SIZE 5
int queue[SIZE], front = -1, rear = -1;

void enqueue(int value) {
    if ((rear + 1) % SIZE == front) { printf("Full\n"); return; }
    if (front == -1) front = 0;
    rear = (rear + 1) % SIZE;
    queue[rear] = value;
}

int dequeue() {
    if (front == -1) { printf("Empty\n"); return -1; }
    int val = queue[front];
    if (front == rear) front = rear = -1; // queue now empty
    else front = (front + 1) % SIZE;
    return val;
}
